#include <bits/stdc++.h>
using namespace std;
int a[100],b[10000],dp[1000000];
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=0;i<m;i++)cin>>a[i];
    for(int i=0;i<n;i++)cin>>b[i];
    for(int i=n-1;i>=0;i--){
        if(i==n-1)dp[i]=b[i];
        else{
            dp[i]=b[i]+dp[i+a[0]];
            for(int j=1;j<m;j++)dp[i]=max(dp[i],b[i]+dp[i+a[j]]);
        }
    }
    cout<<dp[0];
    return 0;
}
